const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`🚀 إسبانيا اليوم running on port ${PORT}`);
  console.log(`📁 DB: ${fs.existsSync(DB_PATH) ? DB_PATH : DB_LOCAL}`);
});

